class Invoice:
    def __init__(self, item_name:str, unit_price:float, quantity: int, tax_rate:float):
        self.item_name = item_name
        self.unit_price = unit_price
        self.quantity = quantity
        self.tax_rate = tax_rate

    def get_subtotal(self):
        return self.unit_price * self.quantity

    def get_tax(self):
        return self.get_subtotal() * self.tax_rate

    def get_total(self):
        return self.get_subtotal() + self.get_tax()

    def __str__(self):
        return "\n".join([
            f"Item: {self.item_name}",
            f"Subtotal: {self.get_subtotal():.02f}",
            f"Tax: {self.get_tax():.02f}",
            f"Total: {self.get_total():.02f}"
        ])

item_name, unit_price, quantity, tax_rate = input().split()
item_name = str(item_name)
unit_price = float(unit_price)
quantity = int(quantity)
tax_rate = float(tax_rate)
invoice = Invoice(item_name, unit_price, quantity, tax_rate)
print(invoice)
